                 Al registrar este medicamento, el sistema activará automáticamente las reglas de <span className="font-black">semaforización de caducidad</span> y alertas de <span className="font-black">stock mínimo</span>. Toda la información será persistida en el servidor seguro de la unidad médica.
               </p>
            </div>

            <div className="flex gap-6">
               <button onClick={() => setShowAddModal(false)} className="flex-1 py-6 bg-slate-100 text-slate-500 font-black text-xs uppercase tracking-widest rounded-[2rem] hover:bg-slate-200 transition-all">Cancelar Registro</button>
               <button 
                 onClick={handleRegisterNewMed}
                 className="flex-[2] py-6 bg-slate-900 text-white font-black text-xs uppercase tracking-widest rounded-[2rem] shadow-[0_20px_50px_-15px_rgba(0,0,0,0.3)] hover:bg-blue-600 transition-all flex items-center justify-center gap-4 group"
               >
                  <Save className="w-6 h-6 group-hover:scale-110 transition-transform" /> 
                  Confirmar Alta en Inventario
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Estilos para impresión */}
      <style>{`
        @media print {
          .no-print, nav, aside, button, select { display: none !important; }
          body { background: white !important; margin: 0 !important; }
          main { margin: 0 !important; padding: 0.5rem !important; width: 100% !important; left: 0 !important; top: 0 !important; }
          .max-w-[215.9mm] { max-width: 100% !important; }
          .bg-slate-900 { background: #000 !important; color: #fff !important; -webkit-print-color-adjust: exact; }
          .border-slate-900 { border-color: #000 !important; }
          @page { margin: 0.5cm; size: letter; }
        }
      `}</style>
    </div>
  );
};

export default Inventory;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Package, 
  Search, 
  Plus, 
  AlertTriangle, 
  Calendar, 
  ClipboardList, 
  TrendingUp, 
  TrendingDown, 
  Info,
  Filter,
  CheckCircle2,
  X,
  Save,
  Truck,
  FileBadge,
  ShieldCheck,
  History,
  ArrowRight,
  Database,
  ArrowUpRight,
  ArrowDownLeft,
  Printer,
  FileText,
  QrCode,
  User,
  Pill,
  ShoppingBag,
  Clock,
  ChevronLeft,
  Stethoscope,
  Archive,
  ExternalLink,
  RefreshCw
} from 'lucide-react';
import { MedicationStock, StockMovement, MedicationCategory, ClinicalNote } from '../types';
import { INITIAL_STOCK } from '../constants';

const Inventory: React.FC = () => {
  // Estados principales
  const [activeTab, setActiveTab] = useState<'stock' | 'movements' | 'dispense'>('stock');
  const [stock, setStock] = useState<MedicationStock[]>(() => {
    const saved = localStorage.getItem('med_inventory_v6');
    return saved ? JSON.parse(saved) : INITIAL_STOCK.map(s => ({ ...s, category: MedicationCategory.GENERAL }));
  });
  const [movements, setMovements] = useState<StockMovement[]>(() => {
    const saved = localStorage.getItem('med_movements_v6');
    return saved ? JSON.parse(saved) : [];
  });

  // Estados de UI
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showPrintKardex, setShowPrintKardex] = useState(false);
  const [selectedMed, setSelectedMed] = useState<MedicationStock | null>(null);
  const [movementType, setMovementType] = useState<'IN' | 'OUT' | null>(null);
  const [movementQty, setMovementQty] = useState(0);
  const [movementReason, setMovementReason] = useState('');

  // Estados para Surtido de Recetas
  const [prescriptionSearch, setPrescriptionSearch] = useState('');
  const [foundPrescription, setFoundPrescription] = useState<ClinicalNote | null>(null);
  const [dispenseQuantities, setDispenseQuantities] = useState<Record<string, number>>({});
  const [showAllHistory, setShowAllHistory] = useState(false); // Toggle para ver historial completo vs recientes

  // Estado para recetas archivadas/surtidas externamente
  const [archivedPrescriptions, setArchivedPrescriptions] = useState<string[]>(() => {
    return JSON.parse(localStorage.getItem('med_pharmacy_archived_v1') || '[]');
  });

  // Estado para nuevo medicamento
  const [newMed, setNewMed] = useState<Partial<MedicationStock>>({
    name: '',
    genericName: '',
    presentation: 'Tabletas',
    concentration: '',
    batch: '',
    expiryDate: '',
    currentStock: 0,
    minStock: 10,
    unit: 'Cajas',
    supplier: '',
    registroCofepris: '',
    category: MedicationCategory.GENERAL
  });

  // Persistencia
  useEffect(() => {
    localStorage.setItem('med_inventory_v6', JSON.stringify(stock));
    localStorage.setItem('med_movements_v6', JSON.stringify(movements));
  }, [stock, movements]);

  useEffect(() => {
    localStorage.setItem('med_pharmacy_archived_v1', JSON.stringify(archivedPrescriptions));
  }, [archivedPrescriptions]);

  // Cargar todas las notas para el monitor de farmacia
  const allNotes: ClinicalNote[] = useMemo(() => {
    return JSON.parse(localStorage.getItem('med_notes_v6') || '[]');
  }, [activeTab]); 

  // Filtrar solo recetas médicas VÁLIDAS para la cola
  const recentPrescriptions = useMemo(() => {
    const now = new Date();
    // Helper para parsear fechas locales dd/mm/yyyy, hh:mm:ss a objeto Date (aproximado para filtrado)
    // Nota: Como las fechas se guardan en locale string, haremos una comparación de texto para "Hoy" 
    // o simplemente mostraremos las últimas X notas si no podemos parsear perfectamente.
    // Para robustez en este demo, usaremos el ID timestamp o asumiremos orden cronológico inverso.

    return allNotes
      .filter(n => n.type === 'Receta Médica Electrónica')
      .filter(n => !archivedPrescriptions.includes(n.id)) // Excluir archivadas
      .sort((a, b) => {
         // Intentar ordenar por ID que contiene timestamp
         const timeA = parseInt(a.id.split('-')[1] || '0');
         const timeB = parseInt(b.id.split('-')[1] || '0');
         return timeB - timeA;
      }); 
  }, [allNotes, archivedPrescriptions]);

  // Filtrar recetas basado en la búsqueda del usuario y Tiempo (24h)
  const filteredPrescriptionsQueue = useMemo(() => {
    let list = recentPrescriptions;

    // Filtro de tiempo: Si NO quiere ver todo el historial, mostramos solo las de las últimas 24h aprox
    // Usamos el timestamp del ID para esto ya que la fecha string es variable
    if (!showAllHistory) {
        const oneDayAgo = Date.now() - (24 * 60 * 60 * 1000);
        list = list.filter(n => {
            const timestamp = parseInt(n.id.split('-')[1] || '0'); // REC-MX-12345678
            // Si el ID no tiene timestamp válido (legacy), lo mostramos por si acaso, o lo ocultamos. 
            // Asumimos IDs generados por el sistema: RECETA-{Date.now()}
            return timestamp > oneDayAgo;
        });
    }

    if (!prescriptionSearch) return list;

    const lowerSearch = prescriptionSearch.toLowerCase();
    return list.filter(n => 
      n.content.folio?.toLowerCase().includes(lowerSearch) ||
      n.patientId?.toLowerCase().includes(lowerSearch)
    );
  }, [recentPrescriptions, prescriptionSearch, showAllHistory]);

  // Filtrado de stock
  const filteredStock = useMemo(() => {
    return stock.filter(m => 
      m.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (m.genericName && m.genericName.toLowerCase().includes(searchTerm.toLowerCase())) ||
      m.batch.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stock, searchTerm]);

  // Filtrado de movimientos
  const filteredMovements = useMemo(() => {
    return movements.filter(m => 
      m.medicationName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      m.batch.toLowerCase().includes(searchTerm.toLowerCase()) ||
      m.responsible.toLowerCase().includes(searchTerm.toLowerCase()) ||
      m.reason.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [movements, searchTerm]);

  // Alertas
  const lowStockCount = stock.filter(m => m.currentStock <= m.minStock).length;
  const expiredCount = stock.filter(m => new Date(m.expiryDate) < new Date()).length;

  const getExpiryStatus = (dateStr: string) => {
    const expiry = new Date(dateStr);
    const now = new Date();
    const threeMonths = new Date();
    threeMonths.setMonth(now.getMonth() + 3);

    if (expiry < now) return { color: 'text-rose-600 bg-rose-50 border-rose-100', label: 'CADUCADO' };
    if (expiry <= threeMonths) return { color: 'text-amber-600 bg-amber-50 border-amber-100', label: 'PRÓXIMO A VENCER' };
    return { color: 'text-emerald-600 bg-emerald-50 border-emerald-100', label: 'VIGENTE' };
  };

  const addMovement = (medId: string, medName: string, batch: string, type: 'IN' | 'OUT', qty: number, reason: string) => {
    const newMove: StockMovement = {
      id: `MOV-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      medicationId: medId,
      medicationName: medName,
      batch: batch,
      type,
      quantity: qty,
      date: new Date().toLocaleString('es-MX'),
      reason: reason || (type === 'IN' ? 'Entrada manual' : 'Salida manual'),
      responsible: 'Farmacia Central'
    };
    setMovements(prev => [newMove, ...prev]);
  };

  const handleStockUpdate = () => {
    if (!selectedMed || !movementType || movementQty <= 0) return;

    if (movementType === 'OUT' && movementQty > selectedMed.currentStock) {
      alert('Error: No hay suficiente stock disponible para realizar esta salida.');
      return;
    }

    setStock(prev => prev.map(m => {
      if (m.id === selectedMed.id) {
        const newQty = movementType === 'IN' 
          ? m.currentStock + movementQty 
          : m.currentStock - movementQty;
        return { ...m, currentStock: newQty };
      }
      return m;
    }));

    addMovement(selectedMed.id, selectedMed.name, selectedMed.batch, movementType, movementQty, movementReason);

    // Reset
    setSelectedMed(null);
    setMovementType(null);
    setMovementQty(0);
    setMovementReason('');
  };

  const handleRegisterNewMed = () => {
    // Validación robusta
    if (!newMed.name?.trim() || !newMed.batch?.trim() || !newMed.expiryDate) {
      alert('Por favor complete los campos obligatorios: Nombre, Lote y Fecha de Caducidad.');
      return;
    }

    const medToAdd: MedicationStock = {
      id: `MED-${Date.now()}`,
      name: newMed.name.trim().toUpperCase(),
      genericName: (newMed.genericName || '').trim().toUpperCase(),
      presentation: newMed.presentation || 'Tabletas',
      concentration: newMed.concentration || '',
      batch: newMed.batch.trim().toUpperCase(),
      expiryDate: newMed.expiryDate,
      currentStock: Number(newMed.currentStock) || 0,
      minStock: Number(newMed.minStock) || 10,
      unit: newMed.unit || 'Cajas',
      supplier: newMed.supplier || 'N/A',
      registroCofepris: newMed.registroCofepris || 'N/A',
      category: newMed.category || MedicationCategory.GENERAL
    };

    setStock(prev => [medToAdd, ...prev]);

    if (medToAdd.currentStock > 0) {
      addMovement(medToAdd.id, medToAdd.name, medToAdd.batch, 'IN', medToAdd.currentStock, 'Inventario Inicial (Alta)');
    }

    setShowAddModal(false);
    setSearchTerm(''); 

    setNewMed({
      name: '', genericName: '', presentation: 'Tabletas', concentration: '',
      batch: '', expiryDate: '', currentStock: 0, minStock: 10, unit: 'Cajas',
      supplier: '', registroCofepris: '', category: MedicationCategory.GENERAL
    });
  };

  // --- LÓGICA DE SURTIDO DE RECETAS ---

  const selectPrescriptionFromQueue = (note: ClinicalNote) => {
    setFoundPrescription(note);
    setDispenseQuantities({});
  };

  const archivePrescription = (e: React.MouseEvent, noteId: string) => {
    e.stopPropagation();
    if (window.confirm("¿Archivar esta receta? Se marcará como 'Surtido Externo' y saldrá de la cola de pendientes.")) {
        setArchivedPrescriptions(prev => [...prev, noteId]);
    }
  };

  const handleDispenseItem = (medName: string, medGeneric: string, requestedId: string) => {
    const qtyToDispense = dispenseQuantities[requestedId] || 0;
    if (qtyToDispense <= 0) {
        alert("Ingrese una cantidad válida a surtir.");
        return;
    }

    // Buscar en inventario (Coincidencia por nombre comercial O genérico)
    const stockItem = stock.find(s => 
        s.name.toUpperCase() === medName.toUpperCase() || 
        s.genericName.toUpperCase() === medGeneric?.toUpperCase()
    );

    if (!stockItem) {
        alert("Este medicamento no se encuentra registrado en el inventario.");
        return;
    }

    if (stockItem.currentStock < qtyToDispense) {
        alert(`Stock insuficiente. Solo hay ${stockItem.currentStock} unidades disponibles.`);
        return;
    }

    // Ejecutar surtido
    setStock(prev => prev.map(s => {
        if (s.id === stockItem.id) {
            return { ...s, currentStock: s.currentStock - qtyToDispense };
        }
        return s;
    }));

    addMovement(
        stockItem.id, 
        stockItem.name, 
        stockItem.batch, 
        'OUT', 
        qtyToDispense, 
        `Surtido Receta #${foundPrescription?.content.folio || 'S/F'} (P-${foundPrescription?.patientId})`
    );

    // Feedback visual y limpiar input de esa linea
    alert(`Surtido exitoso: ${qtyToDispense} unidades de ${stockItem.name}`);
    setDispenseQuantities(prev => ({ ...prev, [requestedId]: 0 }));
  };

  // Helper para verificar disponibilidad en la tarjeta
  const checkAvailability = (meds: any[]) => {
    if (!meds || meds.length === 0) return 'Sin Items';
    let availableCount = 0;
    meds.forEach((med: any) => {
        const inStock = stock.some(s => 
            (s.name.toUpperCase() === med.name.toUpperCase() || s.genericName.toUpperCase() === med.genericName?.toUpperCase()) && 
            s.currentStock > 0
        );
        if (inStock) availableCount++;
    });

    if (availableCount === meds.length) return 'Disponible';
    if (availableCount === 0) return 'Sin Stock';
    return 'Parcial';
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 no-print">
        <div>
          <div className="flex items-center space-x-2 text-slate-400 uppercase text-[10px] font-black tracking-[0.2em] mb-2">
            <Database className="w-3.5 h-3.5 text-blue-600" />
            <span>Gestión de Farmacia Hospitalaria</span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight uppercase">Control de Inventario</h1>
          <p className="text-slate-500 text-sm font-medium mt-1">Cumplimiento con NOM-059-SSA1 y NOM-072-SSA1.</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center bg-white border border-slate-200 p-1.5 rounded-3xl shadow-sm self-start">
            <button 
              onClick={() => setActiveTab('stock')}
              className={`flex items-center px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'stock' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <Package className="w-4 h-4 mr-2" /> Stock Actual
            </button>
            <button 
              onClick={() => { setActiveTab('dispense'); setFoundPrescription(null); }}
              className={`flex items-center px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'dispense' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <ShoppingBag className="w-4 h-4 mr-2" /> Surtir Recetas
            </button>
            <button 
              onClick={() => setActiveTab('movements')}
              className={`flex items-center px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'movements' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <History className="w-4 h-4 mr-2" /> Kardex
            </button>
          </div>

          <button 
            onClick={() => setShowAddModal(true)}
            className="flex items-center px-8 py-4 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest shadow-2xl hover:bg-blue-600 transition-all active:scale-95"
          >
            <Plus className="w-5 h-5 mr-3" /> Alta Insumo
          </button>
        </div>
      </div>

      {activeTab === 'stock' && (
        <>
          {/* Stats Bar */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 no-print">
            <div className="bg-white border border-slate-200 rounded-[2.5rem] p-7 shadow-sm flex items-center space-x-5">
              <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shadow-inner">
                <Package className="w-7 h-7" />
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Insumos Registrados</p>
                <p className="text-2xl font-black text-slate-900 leading-none mt-1">{stock.length}</p>
              </div>
            </div>

            <div className={`bg-white border rounded-[2.5rem] p-7 shadow-sm flex items-center space-x-5 transition-all ${lowStockCount > 0 ? 'border-amber-200 bg-amber-50/20' : 'border-slate-200'}`}>
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner ${lowStockCount > 0 ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-300'}`}>
                <AlertTriangle className="w-7 h-7" />
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Alertas de Stock</p>
                <p className="text-2xl font-black text-slate-900 leading-none mt-1">{lowStockCount}</p>
              </div>
            </div>

            <div className={`bg-white border rounded-[2.5rem] p-7 shadow-sm flex items-center space-x-5 transition-all ${expiredCount > 0 ? 'border-rose-200 bg-rose-50/20' : 'border-slate-200'}`}>
