                                 />
                              </div>
                              <div className="pt-2">
                                 <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</p>
                                 <p className="text-sm font-bold uppercase">{new Date().toLocaleDateString()}</p>
