              </div>
              <div className="flex items-center gap-4">
                <label className="text-xs font-black uppercase">Cantidad:</label>
                <input type="number" className="p-3 border rounded-xl w-24 text-center font-black" value={qty} onChange={e => setQty(parseInt(e.target.value) || 1)} />
              </div>
              <div className="flex gap-2">
                <button onClick={submit} className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-black uppercase text-xs">Agregar</button>
                <button onClick={() => setSelectedPrice(null)} className="py-3 px-6 bg-slate-100 text-slate-500 rounded-xl font-black uppercase text-xs">Volver</button>
              </div>
            </div>
          )}
          <button onClick={() => setShowChargeModal(false)} className="w-full py-2 text-slate-400 text-[10px] font-black uppercase">Cancelar</button>
        </div>
      </div>
    );
  };

  const PaymentModal = () => {
    const [amount, setAmount] = useState(activeAccount?.balance || 0);
    const [method, setMethod] = useState('Efectivo');

    return (
      <div className="fixed inset-0 z-[200] bg-slate-900/90 backdrop-blur flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-[2rem] p-8 space-y-6">
          <h3 className="text-xl font-black uppercase text-slate-900">Registrar Pago</h3>
          <div className="space-y-4">
             <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-slate-400">Monto a Pagar</label>
                <input type="number" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-2xl font-black text-center" value={amount} onChange={e => setAmount(parseFloat(e.target.value))} />
             </div>
             <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-slate-400">Método de Pago</label>
                <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold uppercase" value={method} onChange={e => setMethod(e.target.value)}>
                   <option>Efectivo</option>
                   <option>Tarjeta Crédito/Débito</option>
                   <option>Transferencia</option>
                   <option>Seguro de Gastos Médicos</option>
                </select>
             </div>
          </div>
          <div className="flex gap-4">
             <button onClick={() => setShowPaymentModal(false)} className="flex-1 py-4 bg-slate-100 rounded-xl font-black uppercase text-xs text-slate-500">Cancelar</button>
             <button onClick={() => addPayment(amount, method as any)} className="flex-[2] py-4 bg-emerald-600 text-white rounded-xl font-black uppercase text-xs shadow-xl">Confirmar Pago</button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-in fade-in">
      <div className="flex flex-col md:flex-row justify-between items-end gap-6 no-print">
        <div>
          <h1 className="text-4xl font-black text-slate-900 uppercase">Caja y Facturación</h1>
