    const matchesModule = p.assignedModule === module;

    // LOGICA DE FILTRADO CORRECTA PARA MONITOR ACTIVO
    const isActiveStatus = p.status !== PatientStatus.ATTENDED && 
                           p.status !== PatientStatus.READY_RESULTS &&
