    const isValidAgenda = p.agendaStatus !== AgendaStatus.CANCELLED && 
                          p.agendaStatus !== AgendaStatus.NO_SHOW &&
                          p.agendaStatus !== AgendaStatus.RESCHEDULED;

    return matchesSearch && matchesModule && isActiveStatus && isValidAgenda;
