);

export default Prescription;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { 
  CreditCard, Search, Plus, Printer, FileText, DollarSign, 
  UserCheck, Calendar, Clock, Trash2, CheckCircle2, AlertTriangle,
  Download, Receipt, LayoutList, RefreshCw, X, ShoppingCart, Store, ChevronRight,
  PenTool, ChevronLeft, Wallet, Package
} from 'lucide-react';
import { Patient, PatientAccount, ChargeItem, PriceItem, ClinicalNote, PriceType, MedicationStock, StockMovement } from '../types';
import { INITIAL_PRICES, INITIAL_STOCK } from '../constants';

const Billing: React.FC<{ patients: Patient[], notes: ClinicalNote[] }> = ({ patients, notes }) => {
  const navigate = useNavigate();
  const location = useLocation();

  // --- ESTADOS PERSISTENTES ---
  const [accounts, setAccounts] = useState<PatientAccount[]>(() => {
    const saved = localStorage.getItem('med_accounts_v1');
    return saved ? JSON.parse(saved) : [];
  });

  const [prices] = useState<PriceItem[]>(() => {
    const saved = localStorage.getItem('med_price_catalog_v1');
    return saved ? JSON.parse(saved) : INITIAL_PRICES;
  });

  const [inventory, setInventory] = useState<MedicationStock[]>(() => {
    const saved = localStorage.getItem('med_inventory_v6');
    return saved ? JSON.parse(saved) : INITIAL_STOCK;
  });

  const [movements, setMovements] = useState<StockMovement[]>(() => {
    const saved = localStorage.getItem('med_movements_v6');
    return saved ? JSON.parse(saved) : [];
  });

  // --- ESTADOS UI ---
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showChargeModal, setShowChargeModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [printMode, setPrintMode] = useState<'none' | 'ticket' | 'invoice'>('none');

  // --- EFECTO DE PRE-SELECCIÓN DE PACIENTE (NUEVO) ---
  useEffect(() => {
    if (location.state && location.state.patientId) {
        setSelectedPatientId(location.state.patientId);
        // Limpiar el estado para evitar re-selección al recargar si se desea
        window.history.replaceState({}, document.title);
    }
  }, [location]);

  // --- EFECTOS DE PERSISTENCIA ---
  useEffect(() => {
    localStorage.setItem('med_accounts_v1', JSON.stringify(accounts));
  }, [accounts]);

  useEffect(() => {
    localStorage.setItem('med_inventory_v6', JSON.stringify(inventory));
    localStorage.setItem('med_movements_v6', JSON.stringify(movements));
  }, [inventory, movements]);

  // --- LÓGICA DE NEGOCIO ---

  // Obtener cuenta activa
  const activeAccount = useMemo(() => {
    if (!selectedPatientId) return null;
    let acc = accounts.find(a => a.patientId === selectedPatientId && a.status === 'Abierta');
    if (!acc) {
      return { patientId: selectedPatientId, charges: [], payments: [], balance: 0, status: 'Abierta' } as PatientAccount;
    }
    return acc;
  }, [accounts, selectedPatientId]);

  const patient = patients.find(p => p.id === selectedPatientId);

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.curp.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- GESTIÓN DE INVENTARIO (DEDUCCIÓN/REVERSIÓN) ---

  const deductFromInventory = (inventoryId: string, quantity: number, patientName: string): boolean => {
    const itemIndex = inventory.findIndex(i => i.id === inventoryId);
    if (itemIndex === -1) return false;

    const item = inventory[itemIndex];
    let remaining = quantity;
    const newBatches = [...(item.batches || [])].sort((a, b) => {
        if (a.expiryDate === 'N/A') return 1; 
        if (b.expiryDate === 'N/A') return -1;
        return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
    });

    // Verificar stock total suficiente
    const totalStock = newBatches.reduce((acc, b) => acc + b.currentStock, 0);
    if (totalStock < quantity) {
        alert(`Stock insuficiente para ${item.name}. Disponible: ${totalStock}, Requerido: ${quantity}`);
        return false;
    }

    const newLogs: StockMovement[] = [];

    const updatedBatches = newBatches.map(batch => {
        if (remaining <= 0) return batch;
        if (batch.currentStock > 0) {
            const take = Math.min(remaining, batch.currentStock);
            remaining -= take;

            newLogs.push({
                id: `MOV-OUT-${Date.now()}-${Math.random()}`,
                medicationId: item.id,
                medicationName: item.name,
                batch: batch.batchNumber,
                type: 'OUT',
                quantity: take,
                reason: `Venta Caja - Paciente: ${patientName}`,
                date: new Date().toLocaleString('es-MX'),
                responsible: 'Caja Principal'
            });

            return { ...batch, currentStock: batch.currentStock - take };
        }
        return batch;
    });

    // Actualizar estados
    const newInventory = [...inventory];
    newInventory[itemIndex] = { ...item, batches: updatedBatches };

    setInventory(newInventory);
    setMovements(prev => [...newLogs, ...prev]);
    return true;
  };

  const revertInventory = (inventoryId: string, quantity: number, patientName: string) => {
    const itemIndex = inventory.findIndex(i => i.id === inventoryId);
    if (itemIndex === -1) return;

    const item = inventory[itemIndex];
    // Revertir al último lote activo o al que tenga más fecha (simplificado: primer lote disponible)
    const targetBatchIndex = item.batches.length > 0 ? 0 : -1;

    if (targetBatchIndex === -1) {
        item.batches.push({ id: `BATCH-RET-${Date.now()}`, batchNumber: 'DEVOLUCION', expiryDate: 'N/A', currentStock: 0 });
    }

    const updatedBatches = item.batches.map((b, i) => i === 0 ? { ...b, currentStock: b.currentStock + quantity } : b);

    const newLog: StockMovement = {
        id: `MOV-RET-${Date.now()}`,
        medicationId: item.id,
        medicationName: item.name,
        batch: updatedBatches[0].batchNumber,
        type: 'IN',
        quantity: quantity,
        reason: `Cancelación Venta - Paciente: ${patientName}`,
        date: new Date().toLocaleString('es-MX'),
        responsible: 'Caja Principal'
    };

    const newInventory = [...inventory];
    newInventory[itemIndex] = { ...item, batches: updatedBatches };

    setInventory(newInventory);
    setMovements(prev => [newLog, ...prev]);
  };

  // --- GESTIÓN DE CUENTA ---

  const handleCreateOrUpdateAccount = (updatedAccount: PatientAccount) => {
    setAccounts(prev => {
      const idx = prev.findIndex(a => a.patientId === updatedAccount.patientId && a.status === 'Abierta');
      if (idx >= 0) {
        const newAccounts = [...prev];
        newAccounts[idx] = updatedAccount;
        return newAccounts;
      }
      return [...prev, updatedAccount];
    });
  };

  const addCharge = (charge: ChargeItem) => {
    if (!activeAccount || !patient) return;

    // Si tiene inventario vinculado, intentar descontar stock
    if (charge.linkedInventoryId) {
        const success = deductFromInventory(charge.linkedInventoryId, charge.quantity, patient.name);
        if (!success) return; // Cancelar cargo si no hay stock
    }

    const updatedCharges = [...activeAccount.charges, charge];
    const newBalance = updatedCharges.reduce((sum, c) => sum + (c.status !== 'Cancelado' ? c.total : 0), 0) - 
                       activeAccount.payments.reduce((sum, p) => sum + p.amount, 0);

    handleCreateOrUpdateAccount({
      ...activeAccount,
      charges: updatedCharges,
      balance: newBalance
    });
  };

  const cancelCharge = (chargeId: string) => {
    if (!activeAccount || !patient) return;

    const charge = activeAccount.charges.find(c => c.id === chargeId);
    if (!charge || charge.status === 'Cancelado') return;

    if (!window.confirm("¿Cancelar este cargo? Si es un producto, el stock será devuelto.")) return;

    // Devolución de stock si aplica
    if (charge.linkedInventoryId) {
        revertInventory(charge.linkedInventoryId, charge.quantity, patient.name);
    }

    const updatedCharges = activeAccount.charges.map(c => c.id === chargeId ? { ...c, status: 'Cancelado' as const } : c);

    // Recalcular balance
    const newBalance = updatedCharges.reduce((sum, c) => sum + (c.status !== 'Cancelado' ? c.total : 0), 0) - 
                       activeAccount.payments.reduce((sum, p) => sum + p.amount, 0);

    handleCreateOrUpdateAccount({
        ...activeAccount,
        charges: updatedCharges,
        balance: newBalance
    });
  };

  const addPayment = (amount: number, method: any, reference?: string) => {
    if (!activeAccount) return;
    const newPayment = {
      id: `PAY-${Date.now()}`,
      date: new Date().toLocaleString('es-MX'),
      amount,
      method,
      reference
    };
    const updatedPayments = [...activeAccount.payments, newPayment];
    const chargesTotal = activeAccount.charges.reduce((sum, c) => sum + (c.status !== 'Cancelado' ? c.total : 0), 0);
    const paymentsTotal = updatedPayments.reduce((sum, p) => sum + p.amount, 0);

    handleCreateOrUpdateAccount({
      ...activeAccount,
      payments: updatedPayments,
      balance: chargesTotal - paymentsTotal
    });
    setShowPaymentModal(false);
  };

  const syncFromNotes = () => {
    if (!selectedPatientId || !activeAccount) return;

    const patientNotes = notes.filter(n => n.patientId === selectedPatientId);
    let newChargesCount = 0;

    patientNotes.forEach(note => {
      // Evitar duplicados basados en ID de nota
      if (activeAccount.charges.some(c => c.sourceId === note.id)) return;

      // 1. CARGOS POR CONSULTAS (Honorarios)
      let consultPriceCode = '';
      if (note.type.includes('Consulta') || note.type.includes('Historia')) consultPriceCode = 'CON-GEN';
      if (note.type.includes('Urgencias')) consultPriceCode = 'URG-BAS';
      if (note.type.includes('Especialidad') || note.type.includes('Interconsulta')) consultPriceCode = 'CON-ESP';

      if (consultPriceCode) {
          const priceItem = prices.find(p => p.code === consultPriceCode);
          if (priceItem) {
            addCharge({
                id: `CHG-${Date.now()}-${Math.random()}`,
                date: note.date,
                concept: `Honorarios: ${note.type} - ${note.author}`,
                quantity: 1,
                unitPrice: priceItem.price,
                total: priceItem.price * (1 + priceItem.taxPercent/100),
                type: 'Honorarios',
                status: 'Pendiente',
                sourceId: note.id
            });
            newChargesCount++;
          }
      }

      // 2. CARGOS POR RECETAS (Farmacia)
      if (note.type === 'Receta Médica Electrónica' && note.content.meds) {
          note.content.meds.forEach((med: any) => {
              // Buscar en catálogo de precios por nombre (aproximado)
              const priceItem = prices.find(p => p.name.toUpperCase().includes(med.name.toUpperCase()));

              const alreadyCharged = activeAccount.charges.some(c => c.sourceId === note.id && c.concept.includes(med.name));

              if (priceItem && !alreadyCharged) {
                  const qty = 1; 
                  addCharge({
                      id: `CHG-MED-${Date.now()}-${Math.random()}`,
                      date: note.date,
                      concept: `FARMACIA: ${priceItem.name}`,
                      quantity: qty,
                      unitPrice: priceItem.price,
                      total: priceItem.price * (1 + priceItem.taxPercent/100) * qty,
                      type: 'Farmacia',
                      status: 'Pendiente',
                      sourceId: note.id,
                      linkedInventoryId: priceItem.linkedInventoryId
                  });
                  newChargesCount++;
              }
          });
      }

      // 3. CARGOS POR PROCEDIMIENTOS ADICIONALES (En Receta o Nota Evolución)
      if (note.content.procedures && Array.isArray(note.content.procedures)) {
          note.content.procedures.forEach((proc: any) => {
              const alreadyCharged = activeAccount.charges.some(c => c.sourceId === note.id && c.concept.includes(proc.name));
              if (!alreadyCharged) {
                  addCharge({
                      id: `CHG-PROC-${Date.now()}-${Math.random()}`,
                      date: note.date,
                      concept: `PROCEDIMIENTO: ${proc.name}`,
                      quantity: 1,
                      unitPrice: proc.price,
                      total: proc.price * (1 + (proc.taxPercent || 0)/100),
                      type: 'Honorarios',
                      status: 'Pendiente',
                      sourceId: note.id
                  });
                  newChargesCount++;
              }
          });
      }

      // 4. CARGOS POR ESTUDIOS (Auxiliares)
      if (note.type === 'Solicitud de Estudios Auxiliares' && note.content.metadata) {
          note.content.metadata.forEach((study: any) => {
              const priceItem = prices.find(p => p.name.toUpperCase() === study.name.toUpperCase());
              const alreadyCharged = activeAccount.charges.some(c => c.sourceId === note.id && c.concept.includes(study.name));

              if (priceItem && !alreadyCharged) {
                  addCharge({
                      id: `CHG-LAB-${Date.now()}-${Math.random()}`,
                      date: note.date,
                      concept: `ESTUDIO: ${study.name}`,
                      quantity: 1,
                      unitPrice: priceItem.price,
                      total: priceItem.price * (1 + priceItem.taxPercent/100),
                      type: 'Estudios',
                      status: 'Pendiente',
                      sourceId: note.id
                  });
                  newChargesCount++;
              }
          });
      }
    });

    if (newChargesCount > 0) alert(`Se sincronizaron ${newChargesCount} cargos desde el expediente clínico (Consultas, Recetas, Procedimientos, Estudios).`);
    else alert("No se encontraron nuevos cargos pendientes de sincronizar.");
  };

  const closeAccount = () => {
    if (!activeAccount) return;
    if (activeAccount.balance > 0.5) { // Tolerancia de centavos
      alert("No se puede cerrar la cuenta con saldo pendiente. Registre el pago completo primero.");
      return;
    }
    if (window.confirm("¿Confirmar el cierre de caja para este paciente? La cuenta pasará a histórico.")) {
      handleCreateOrUpdateAccount({ ...activeAccount, status: 'Cerrada' });
      setSelectedPatientId(null);
    }
  };

  // --- MODALES (UI) ---

  const AddChargeModal = () => {
    const [searchItem, setSearchItem] = useState('');
    const [selectedPrice, setSelectedPrice] = useState<PriceItem | null>(null);
    const [qty, setQty] = useState(1);

    // Estado para cargo manual
    const [isManual, setIsManual] = useState(false);
    const [manualData, setManualData] = useState({ name: '', price: 0, tax: 16 });

    const filteredPrices = prices.filter(p => p.name.toLowerCase().includes(searchItem.toLowerCase()) || p.code.toLowerCase().includes(searchItem.toLowerCase()));

    const submit = () => {
      if (isManual) {
         if (!manualData.name || manualData.price <= 0) {
            alert("Ingrese un nombre y precio válido.");
            return;
         }
         const total = manualData.price * qty * (1 + manualData.tax / 100);
         addCharge({
            id: `CHG-${Date.now()}`,
            date: new Date().toLocaleString('es-MX'),
            concept: manualData.name.toUpperCase() + ' (MANUAL)',
            quantity: qty,
            unitPrice: manualData.price,
            total: parseFloat(total.toFixed(2)),
            type: 'Otro',
            status: 'Pendiente'
         });
      } else if (selectedPrice) {
         const total = selectedPrice.price * qty * (1 + selectedPrice.taxPercent / 100);
         addCharge({
            id: `CHG-${Date.now()}`,
            date: new Date().toLocaleString('es-MX'),
            concept: selectedPrice.name,
            quantity: qty,
            unitPrice: selectedPrice.price,
            total: parseFloat(total.toFixed(2)),
            type: selectedPrice.category as any || 'Otro',
            status: 'Pendiente',
            linkedInventoryId: selectedPrice.linkedInventoryId
         });
      }
      setShowChargeModal(false);
    };

    return (
      <div className="fixed inset-0 z-[200] bg-slate-900/90 backdrop-blur flex items-center justify-center p-4 animate-in fade-in">
        <div className="bg-white w-full max-w-lg rounded-[2rem] p-8 space-y-6 shadow-2xl animate-in zoom-in-95">
          <div className="flex justify-between items-center">
             <h3 className="text-xl font-black uppercase text-slate-900">Agregar Cargo</h3>
             <button onClick={() => setShowChargeModal(false)}><X size={24} className="text-slate-400 hover:text-rose-500" /></button>
          </div>

          {!selectedPrice && !isManual ? (
            <div className="space-y-4">
              <div className="relative">
                 <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                 <input 
                   autoFocus
                   className="w-full pl-10 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-xl outline-none uppercase font-bold text-sm focus:border-blue-500 focus:bg-white transition-all"
                   placeholder="Buscar servicio o producto..."
                   value={searchItem}
                   onChange={e => setSearchTerm(e.target.value)}
                 />
              </div>
              <div className="max-h-64 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                {filteredPrices.map(p => (
                  <button key={p.id} onClick={() => setSelectedPrice(p)} className="w-full text-left p-3 hover:bg-blue-50 border border-transparent hover:border-blue-100 rounded-xl flex justify-between group transition-all">
                    <div>
                       <span className="text-xs font-black uppercase text-slate-700 block">{p.name}</span>
                       <span className="text-[10px] text-slate-400 uppercase font-bold">{p.category}</span>
                    </div>
                    <span className="text-sm font-black text-slate-900 group-hover:text-blue-600">${p.price.toFixed(2)}</span>
                  </button>
                ))}
              </div>
              <button 
                onClick={() => { setIsManual(true); setManualData({...manualData, name: searchItem.toUpperCase()}); }}
                className="w-full py-3 bg-slate-100 text-slate-500 hover:bg-indigo-600 hover:text-white rounded-xl font-black text-[10px] uppercase transition-all flex items-center justify-center gap-2"
              >
                 <PenTool size={14} /> Item no encontrado - Agregar Manualmente
              </button>
            </div>
          ) : isManual ? (
             <div className="space-y-6">
                <div className="space-y-4">
                   <div className="space-y-1">
                      <label className="text-[9px] font-black uppercase text-slate-400">Concepto / Descripción</label>
                      <input 
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-black uppercase text-sm outline-none focus:border-indigo-500" 
                        value={manualData.name} 
                        onChange={e => setManualData({...manualData, name: e.target.value})} 
                        placeholder="Descripción del cargo..."
                        autoFocus
                      />
                   </div>
                   <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1">
                         <label className="text-[9px] font-black uppercase text-slate-400">Precio Unitario</label>
                         <input type="number" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-black text-sm outline-none" value={manualData.price} onChange={e => setManualData({...manualData, price: parseFloat(e.target.value) || 0})} />
                      </div>
                      <div className="space-y-1">
                         <label className="text-[9px] font-black uppercase text-slate-400">IVA %</label>
                         <input type="number" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-black text-sm outline-none" value={manualData.tax} onChange={e => setManualData({...manualData, tax: parseFloat(e.target.value) || 0})} />
                      </div>
                   </div>
                </div>

                <div className="flex items-center justify-center gap-6">
